Code:
public int[] fix45(int[] nums) {
        int n = nums.length;
        if (n < 2) return nums;

        int fourIdx = 0;
        int fiveIdx = 1;

        while (fiveIdx < n) {
            if (nums[fiveIdx] == 5 && nums[fiveIdx - 1] == 4) {
                fiveIdx++;
            } else {
                int temp = nums[fiveIdx];
                nums[fiveIdx] = nums[fourIdx];
                nums[fourIdx] = temp;
                fourIdx++;
                fiveIdx++;
            }
        }

        return nums;
    }

